
INSERT INTO public.email_templates (template_key, name, subject, body, description, trigger_info, is_active)
VALUES
  ('order_placed', 'Order Placed', 'Your reward is being processed! 🎉', E'<div style="font-family:Inter,Arial,sans-serif;max-width:600px;margin:0 auto;background:#ffffff;border-radius:12px;overflow:hidden">\n  <div style="background:linear-gradient(135deg,hsl(205,65%,45%),hsl(190,70%,42%));padding:32px 24px;text-align:center">\n    <img src="https://ncpbiymnafxdfsvpxirb.supabase.co/storage/v1/object/public/email-assets/logo.png" alt="C24 Club" width="120" style="margin-bottom:16px" />\n    <h1 style="color:#ffffff;font-size:24px;margin:0">Order Placed! 🎉</h1>\n  </div>\n  <div style="padding:32px 24px">\n    <p style="font-size:16px;color:#1a1a2e;margin:0 0 16px">Hey {{user_name}},</p>\n    <p style="font-size:16px;color:#1a1a2e;margin:0 0 24px">Great news! Your reward <strong>{{reward_title}}</strong> is now being processed. We''re working on getting it ready for you.</p>\n    <div style="background:#f0f9ff;border-radius:8px;padding:16px;margin:0 0 24px">\n      <p style="font-size:14px;color:#64748b;margin:0 0 4px">Order Date</p>\n      <p style="font-size:16px;color:#1a1a2e;font-weight:600;margin:0">{{order_date}}</p>\n    </div>\n    <p style="font-size:14px;color:#64748b;margin:0">We''ll send you another email once your reward ships. Stay tuned!</p>\n  </div>\n  <div style="background:#f8fafc;padding:24px;text-align:center;border-top:1px solid #e2e8f0">\n    <p style="font-size:12px;color:#94a3b8;margin:0">© C24 Club · All rights reserved</p>\n  </div>\n</div>', 'Sent when admin marks a redemption as Order Placed', 'Admin changes redemption status to "Order placed"', true),

  ('order_shipped', 'Order Shipped', 'Your reward is on the way! 📦', E'<div style="font-family:Inter,Arial,sans-serif;max-width:600px;margin:0 auto;background:#ffffff;border-radius:12px;overflow:hidden">\n  <div style="background:linear-gradient(135deg,hsl(205,65%,45%),hsl(190,70%,42%));padding:32px 24px;text-align:center">\n    <img src="https://ncpbiymnafxdfsvpxirb.supabase.co/storage/v1/object/public/email-assets/logo.png" alt="C24 Club" width="120" style="margin-bottom:16px" />\n    <h1 style="color:#ffffff;font-size:24px;margin:0">Your Reward Has Shipped! 📦</h1>\n  </div>\n  <div style="padding:32px 24px">\n    <p style="font-size:16px;color:#1a1a2e;margin:0 0 16px">Hey {{user_name}},</p>\n    <p style="font-size:16px;color:#1a1a2e;margin:0 0 24px">Your reward <strong>{{reward_title}}</strong> is on its way to you!</p>\n    <div style="background:#f0f9ff;border-radius:8px;padding:16px;margin:0 0 24px">\n      <p style="font-size:14px;color:#64748b;margin:0 0 8px">Tracking Information</p>\n      <a href="{{tracking_url}}" style="display:inline-block;background:hsl(205,65%,45%);color:#ffffff;padding:12px 24px;border-radius:8px;text-decoration:none;font-weight:600;font-size:14px">Track Your Package</a>\n    </div>\n    <p style="font-size:14px;color:#64748b;margin:0">If the tracking link isn''t available yet, it will be updated shortly.</p>\n  </div>\n  <div style="background:#f8fafc;padding:24px;text-align:center;border-top:1px solid #e2e8f0">\n    <p style="font-size:12px;color:#94a3b8;margin:0">© C24 Club · All rights reserved</p>\n  </div>\n</div>', 'Sent when admin marks a redemption as Order Shipped with optional tracking link', 'Admin changes redemption status to "Order shipped"', true),

  ('order_delivered', 'Order Delivered', 'Your reward has arrived! 🎁', E'<div style="font-family:Inter,Arial,sans-serif;max-width:600px;margin:0 auto;background:#ffffff;border-radius:12px;overflow:hidden">\n  <div style="background:linear-gradient(135deg,hsl(205,65%,45%),hsl(190,70%,42%));padding:32px 24px;text-align:center">\n    <img src="https://ncpbiymnafxdfsvpxirb.supabase.co/storage/v1/object/public/email-assets/logo.png" alt="C24 Club" width="120" style="margin-bottom:16px" />\n    <h1 style="color:#ffffff;font-size:24px;margin:0">Your Reward Has Arrived! 🎁</h1>\n  </div>\n  <div style="padding:32px 24px">\n    <p style="font-size:16px;color:#1a1a2e;margin:0 0 16px">Hey {{user_name}},</p>\n    <p style="font-size:16px;color:#1a1a2e;margin:0 0 24px">Your reward <strong>{{reward_title}}</strong> has been delivered! We hope you love it.</p>\n    <div style="background:#f0fdf4;border-radius:8px;padding:16px;margin:0 0 24px;text-align:center">\n      <p style="font-size:32px;margin:0 0 8px">✅</p>\n      <p style="font-size:16px;color:#166534;font-weight:600;margin:0">Delivered Successfully</p>\n    </div>\n    <p style="font-size:14px;color:#64748b;margin:0">Keep earning minutes to unlock even more rewards. Happy chatting!</p>\n  </div>\n  <div style="background:#f8fafc;padding:24px;text-align:center;border-top:1px solid #e2e8f0">\n    <p style="font-size:12px;color:#94a3b8;margin:0">© C24 Club · All rights reserved</p>\n  </div>\n</div>', 'Sent when admin marks a redemption as Delivered', 'Admin changes redemption status to "Delivered"', true),

  ('gift_card_sent', 'Gift Card Sent', 'Your gift card code is ready! 💳', E'<div style="font-family:Inter,Arial,sans-serif;max-width:600px;margin:0 auto;background:#ffffff;border-radius:12px;overflow:hidden">\n  <div style="background:linear-gradient(135deg,hsl(205,65%,45%),hsl(190,70%,42%));padding:32px 24px;text-align:center">\n    <img src="https://ncpbiymnafxdfsvpxirb.supabase.co/storage/v1/object/public/email-assets/logo.png" alt="C24 Club" width="120" style="margin-bottom:16px" />\n    <h1 style="color:#ffffff;font-size:24px;margin:0">Your Gift Card Is Ready! 💳</h1>\n  </div>\n  <div style="padding:32px 24px">\n    <p style="font-size:16px;color:#1a1a2e;margin:0 0 16px">Hey {{user_name}},</p>\n    <p style="font-size:16px;color:#1a1a2e;margin:0 0 24px">Your gift card for <strong>{{reward_title}}</strong> has been sent! Check your C24 Club rewards page to view and copy your code.</p>\n    <div style="background:#fef3c7;border-radius:8px;padding:16px;margin:0 0 24px;text-align:center">\n      <p style="font-size:32px;margin:0 0 8px">🎉</p>\n      <p style="font-size:16px;color:#92400e;font-weight:600;margin:0">Gift Card Ready to Use</p>\n    </div>\n    <p style="font-size:14px;color:#64748b;margin:0">Log in to your account to access your gift card code anytime.</p>\n  </div>\n  <div style="background:#f8fafc;padding:24px;text-align:center;border-top:1px solid #e2e8f0">\n    <p style="font-size:12px;color:#94a3b8;margin:0">© C24 Club · All rights reserved</p>\n  </div>\n</div>', 'Sent when admin marks a redemption as Gift Card Sent on Email', 'Admin changes redemption status to "Gift Card Sent on Email"', true)
ON CONFLICT (template_key) DO NOTHING;
